import{_ as a,o as t,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Bear Trap","description":"","frontmatter":{},"headers":[],"relativePath":"events/bear-trap.md","filePath":"events/bear-trap.md"}'),s={name:"events/bear-trap.md"};function l(i,e,n,h,p,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="bear-trap" tabindex="-1">Bear Trap <a class="header-anchor" href="#bear-trap" aria-label="Permalink to &quot;Bear Trap&quot;">​</a></h1><p>Bear Trap is the tracker&#39;s default template for the short alliance rally event where players push as much <strong>damage</strong> as they can against the bear.</p><blockquote><p>Screenshot placeholder: event-bear-trap.png</p></blockquote><h2 id="how-this-default-is-set-up" tabindex="-1">How this default is set up <a class="header-anchor" href="#how-this-default-is-set-up" aria-label="Permalink to &quot;How this default is set up&quot;">​</a></h2><ul><li>event style: single-session</li><li>score entry: one score per player</li><li>score label: <strong>Damage</strong></li><li>score required: yes</li><li>participation tracked: yes</li></ul><p>This is a straightforward score event. You normally import one ranking screenshot and review the rows before accepting them.</p><h2 id="what-to-import" tabindex="-1">What to import <a class="header-anchor" href="#what-to-import" aria-label="Permalink to &quot;What to import&quot;">​</a></h2><p>Upload the personal damage ranking screenshot from the event.</p><p>There is no stage picker and no cumulative-total behavior here. One session usually means one date and one damage ranking.</p><h2 id="what-the-results-mean" tabindex="-1">What the results mean <a class="header-anchor" href="#what-the-results-mean" aria-label="Permalink to &quot;What the results mean&quot;">​</a></h2><p>Bear Trap is usually used for:</p><ul><li>top damage rankings</li><li>participation checks</li><li>reward decisions based on damage or attendance</li></ul><p>If your alliance also wants to track milestone thresholds, use reward rules or notes around the saved results.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>keep the score label as <strong>Damage</strong> unless your alliance has a very specific reason to rename it</li><li>use one instance per event date</li><li>review unmatched names carefully, because nickname differences are common in rally screenshots</li></ul><h2 id="protection-note" tabindex="-1">Protection note <a class="header-anchor" href="#protection-note" aria-label="Permalink to &quot;Protection note&quot;">​</a></h2><p>This is a default template, so it is <strong>editable but not deletable</strong>. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./default-events.html">The Default Events</a></li><li><a href="./../imports/upload-screenshots.html">Upload Screenshots</a></li><li><a href="./../imports/apply-import.html">Accept Rows (Apply an Import)</a></li></ul>',19)])])}const m=a(s,[["render",l]]);export{u as __pageData,m as default};
